/**
 * 日付ユーティリティ。期限計算・繰り返し・期限ステータスを扱う。
 * 日付は ISO 'YYYY-MM-DD' 文字列で受け渡す(ローカル日付前提、タイムゾーン非依存)。
 */

export type IsoDate = string; // 'YYYY-MM-DD'

export function toIsoDate(d: Date): IsoDate {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

export function parseIsoDate(s: IsoDate): Date {
  const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s);
  if (!m) throw new Error(`不正な日付形式: ${s}`);
  return new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
}

export function addDays(s: IsoDate, days: number): IsoDate {
  const d = parseIsoDate(s);
  d.setDate(d.getDate() + days);
  return toIsoDate(d);
}

export function addMonths(s: IsoDate, months: number): IsoDate {
  const d = parseIsoDate(s);
  const targetMonth = d.getMonth() + months;
  d.setMonth(targetMonth);
  return toIsoDate(d);
}

/** 2日付の差(日数, a - b)。 */
export function diffDays(a: IsoDate, b: IsoDate): number {
  const ms = parseIsoDate(a).getTime() - parseIsoDate(b).getTime();
  return Math.round(ms / 86_400_000);
}

export type DueStatus = 'overdue' | 'due_soon' | 'upcoming' | 'none';

/**
 * 期限ステータス。today を基準に判定。
 * - overdue: 期限超過
 * - due_soon: soonDays 以内
 * - upcoming: それ以降
 * - none: due 未設定
 */
export function dueStatus(due: IsoDate | null | undefined, today: IsoDate, soonDays = 14): DueStatus {
  if (!due) return 'none';
  const d = diffDays(due, today);
  if (d < 0) return 'overdue';
  if (d <= soonDays) return 'due_soon';
  return 'upcoming';
}

export type Recurrence = 'monthly' | 'yearly' | 'quarterly' | 'weekly' | 'none';

/** 次回発生日。recurrence が none の場合は null。 */
export function nextOccurrence(from: IsoDate, recurrence: Recurrence): IsoDate | null {
  switch (recurrence) {
    case 'weekly':
      return addDays(from, 7);
    case 'monthly':
      return addMonths(from, 1);
    case 'quarterly':
      return addMonths(from, 3);
    case 'yearly':
      return addMonths(from, 12);
    case 'none':
      return null;
  }
}

/** 'YYYY-MM' を返す(月次集計のキー)。 */
export function yearMonth(isoDateOrTimestamp: string): string {
  const m = /^(\d{4})-(\d{2})/.exec(isoDateOrTimestamp);
  if (!m) throw new Error(`日付/日時から年月を抽出できません: ${isoDateOrTimestamp}`);
  return `${m[1]}-${m[2]}`;
}
/**
 * 依存ゼロの CSV パーサ/シリアライザ(RFC4180 準拠寄り)。
 * - BOM を除去して読む(出典パックの CSV は UTF-8 BOM 付き)。
 * - 引用符内のカンマ・改行・"" エスケープに対応。
 * - 出力は Excel で文字化けしないよう既定で BOM を付与可能。
 */

export type CsvRow = Record<string, string>;

/** CSV テキストを行オブジェクト配列にパースする(1行目をヘッダとみなす)。 */
export function parseCsv(text: string): CsvRow[] {
  const records = parseCsvRaw(text);
  if (records.length === 0) return [];
  const header = records[0]!;
  const rows: CsvRow[] = [];
  for (let i = 1; i < records.length; i++) {
    const cells = records[i]!;
    // 完全な空行はスキップ
    if (cells.length === 1 && cells[0] === '') continue;
    const row: CsvRow = {};
    for (let c = 0; c < header.length; c++) {
      row[header[c]!] = cells[c] ?? '';
    }
    rows.push(row);
  }
  return rows;
}

/** CSV テキストを生の2次元配列にパースする。 */
export function parseCsvRaw(input: string): string[][] {
  const text = stripBom(input);
  const rows: string[][] = [];
  let field = '';
  let row: string[] = [];
  let inQuotes = false;
  let i = 0;

  while (i < text.length) {
    const ch = text[i]!;
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') {
          field += '"';
          i += 2;
          continue;
        }
        inQuotes = false;
        i++;
        continue;
      }
      field += ch;
      i++;
      continue;
    }
    if (ch === '"') {
      inQuotes = true;
      i++;
      continue;
    }
    if (ch === ',') {
      row.push(field);
      field = '';
      i++;
      continue;
    }
    if (ch === '\r') {
      i++;
      continue;
    }
    if (ch === '\n') {
      row.push(field);
      rows.push(row);
      field = '';
      row = [];
      i++;
      continue;
    }
    field += ch;
    i++;
  }
  // 末尾フィールド/行
  if (field.length > 0 || row.length > 0) {
    row.push(field);
    rows.push(row);
  }
  return rows;
}

export interface SerializeOptions {
  /** 出力カラム順。未指定なら最初の行のキー順。 */
  columns?: string[];
  /** Excel 互換のため先頭に UTF-8 BOM を付ける。既定 true。 */
  bom?: boolean;
}

/** 行オブジェクト配列を CSV テキストにシリアライズする。 */
export function serializeCsv(rows: ReadonlyArray<CsvRow>, opts: SerializeOptions = {}): string {
  const columns = opts.columns ?? (rows.length > 0 ? Object.keys(rows[0]!) : []);
  const bom = opts.bom ?? true;
  const lines: string[] = [];
  lines.push(columns.map(escapeCell).join(','));
  for (const row of rows) {
    lines.push(columns.map((col) => escapeCell(row[col] ?? '')).join(','));
  }
  return (bom ? '﻿' : '') + lines.join('\r\n');
}

function escapeCell(value: string): string {
  if (/[",\r\n]/.test(value)) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
}

function stripBom(text: string): string {
  return text.charCodeAt(0) === 0xfeff ? text.slice(1) : text;
}

