+}
+
+function mapExpense(row: ExpenseRow): Expense {
+  return {
+    id: row.id,
+    spentAt: row.spent_at,
+    vendor: row.vendor,
+    category: row.category,
+    amountTaxIncluded: row.amount_tax_included,
+    taxAmount: row.tax_amount,
+    paymentMethod: row.payment_method,
