+      paymentMethod: 'credit_card',
+      purpose: '発送用封筒',
+    });
+
+    const updated = updateExpense(db, created.id, {
+      vendor: 'オンライン文具',
+      amountTaxIncluded: 1650,
+      taxAmount: 150,
+      purpose: null,
+    });
+    expect(updated).toMatchObject({
+      id: created.id,
+      vendor: 'オンライン文具',
+      amountTaxIncluded: 1650,
