+    ).toThrow(/amountTaxIncluded must be an integer/);
+
+    expect(() =>
+      createExpense(db, {
+        spentAt: '2026-06-09',
+        category: 'software',
+        amountTaxIncluded: 1200,
+        taxAmount: 109.5,
+      }),
+    ).toThrow(/taxAmount must be an integer/);
+    db.close();
