+
+  it('月次とカテゴリ別に税込金額と税額を集計する', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    createExpense(db, {
+      spentAt: '2026-06-01',
+      category: 'software',
+      amountTaxIncluded: 3300,
