+
+    expect(summarizeExpensesByMonth(db)).toEqual([
+      { month: '2026-06', amountTaxIncluded: 4400, taxAmount: 400, expenseCount: 2 },
+      { month: '2026-07', amountTaxIncluded: 2200, taxAmount: 200, expenseCount: 1 },
