+    expect(summarizeExpensesByCategory(db, '2026-06')).toEqual([
+      { category: 'software', amountTaxIncluded: 3300, taxAmount: 300, expenseCount: 1 },
+      { category: 'supplies', amountTaxIncluded: 1100, taxAmount: 100, expenseCount: 1 },
