+import { expenseRoutes } from '../src/routes/expenses.js';
+
+declare module 'fastify' {
+  interface FastifyInstance {
+    db: DB;
+  }
+}
+
+let app: FastifyInstance;
+let db: DB;
+
+beforeEach(async () => {
