+  db.close();
+});
+
+describe('expenseRoutes', () => {
+  it('経費CRUDを扱い監査ログを記録する', async () => {
+    const created = await app.inject({
+      method: 'POST',
+      url: '/api/expenses',
+      payload: {
+        spentAt: '2026-06-09',
+        vendor: '交通機関',
+        category: 'travel',
+        amountTaxIncluded: 880,
