+
+    expect(() =>
+      createExpense(db, {
+        spentAt: '2026-06-09',
+        category: 'software',
+        amountTaxIncluded: 1200.5,
+      }),
+    ).toThrow(/amountTaxIncluded must be an integer/);
+
+    expect(() =>
+      createExpense(db, {
+        spentAt: '2026-06-09',
+        category: 'software',
