+    createExpense(db, {
+      spentAt: '2026-06-20',
+      category: 'supplies',
+      amountTaxIncluded: 1100,
+      taxAmount: 100,
+    });
+    createExpense(db, {
+      spentAt: '2026-07-01',
+      category: 'software',
+      amountTaxIncluded: 2200,
+      taxAmount: 200,
