+    const result = db
+      .prepare(
+        `INSERT INTO expenses
+          (spent_at, vendor, category, amount_tax_included, tax_amount, payment_method, purpose, attachment_id)
+         VALUES
+          (@spentAt, @vendor, @category, @amountTaxIncluded, @taxAmount, @paymentMethod, @purpose, @attachmentId)`,
