+         vendor = @vendor,
+         category = @category,
+         amount_tax_included = @amountTaxIncluded,
+         tax_amount = @taxAmount,
+         payment_method = @paymentMethod,
+         purpose = @purpose,
+         attachment_id = @attachmentId
+       WHERE id = @id`,
+    ).run({
