+  id?: unknown;
+  spentAt?: unknown;
+  vendor?: unknown;
+  category?: unknown;
+  amountTaxIncluded?: unknown;
+  taxAmount?: unknown;
+  paymentMethod?: unknown;
+  purpose?: unknown;
